"""Candidate controller for SD3.5 PickScore discovery."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError, InvalidActionError
from flow_autotts.core.state import AnswerRecord, PreviewRecord


class OptimalController:
    """Completed-anchor best-of-N with beta-scaled late refinement."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        initial_budget = max(0, int(env.budget_left))

        root_id = env.spawn(1)[0]
        try:
            self._finish(env, root_id)
        except BudgetExceededError:
            return env.answer(rule="latest_active")

        if beta <= 0.0 or env.budget_left <= 0:
            return env.answer(rule="latest_active")

        target_nfe = self._target_nfe(initial_budget, beta, spent=initial_budget - env.budget_left)
        self._preview(env, root_id, target_nfe, initial_budget)

        step_count = max(1, len(env.time_grid) - 1)
        full_candidate_cost = step_count + 1
        full_candidates = max(1, min(5, 1 + int(4 * beta), target_nfe // full_candidate_cost))
        extra_roots = max(0, full_candidates - 1)
        if extra_roots > 0:
            for particle_id in env.spawn(extra_roots):
                if self._spent(env, initial_budget) + full_candidate_cost > target_nfe:
                    break
                try:
                    self._finish(env, particle_id)
                    self._preview(env, particle_id, target_nfe, initial_budget)
                except (BudgetExceededError, InvalidActionError):
                    break

        self._refine_from_best_previews(env, beta, target_nfe, initial_budget)
        return env.answer(rule="best_preview_score")

    def _target_nfe(self, initial_budget: int, beta: float, spent: int) -> int:
        if initial_budget <= spent:
            return spent
        extra = int((initial_budget - spent) * beta)
        if beta > 0.0:
            extra = max(1, extra)
        return min(initial_budget, spent + extra)

    def _finish(self, env: FlowTTSEnv, particle_id: int) -> None:
        state = env.get_state()
        current_time = state.particles[particle_id].time
        for target_time in env.time_grid:
            if target_time > current_time:
                env.forward(particle_id, target_time=target_time, solver="euler")
                current_time = target_time

    def _preview(
        self,
        env: FlowTTSEnv,
        particle_id: int,
        target_nfe: int,
        initial_budget: int,
    ) -> None:
        if self._spent(env, initial_budget) + 1 <= target_nfe and env.budget_left > 0:
            env.preview(particle_id, mode="clean_anchor", scorer="default")

    def _refine_from_best_previews(
        self,
        env: FlowTTSEnv,
        beta: float,
        target_nfe: int,
        initial_budget: int,
    ) -> None:
        target_time = self._backward_time(beta)
        noise_policy = "mixed_noise" if beta >= 0.6 else "fresh_noise"
        strength = 0.35 if noise_policy == "mixed_noise" else 1.0
        max_children = max(0, int(1 + 4 * beta))

        children_made = 0
        while children_made < max_children:
            previews = self._ranked_previews(env)
            if not previews:
                return
            anchor = previews[children_made % len(previews)]
            child_cost = self._child_finish_preview_cost(env, target_time)
            if self._spent(env, initial_budget) + child_cost > target_nfe:
                return
            try:
                child_id = env.backward(
                    anchor.id,
                    target_time=target_time,
                    noise_policy=noise_policy,
                    num_children=1,
                    strength=strength,
                )[0]
                self._finish(env, child_id)
                self._preview(env, child_id, target_nfe, initial_budget)
            except (BudgetExceededError, InvalidActionError):
                return
            children_made += 1

    def _ranked_previews(self, env: FlowTTSEnv) -> list[PreviewRecord]:
        state = env.get_state()
        previews = [
            preview
            for preview in state.previews.values()
            if preview.score is not None
            and preview.particle_id in state.particles
            and state.particles[preview.particle_id].status != "pruned"
        ]
        return sorted(
            previews,
            key=lambda preview: (
                float(preview.score),
                -float(preview.uncertainty or 0.0),
                float(preview.time),
            ),
            reverse=True,
        )

    def _child_finish_preview_cost(self, env: FlowTTSEnv, target_time: float) -> int:
        forward_steps = sum(1 for time in env.time_grid if time > target_time)
        return max(1, forward_steps) + 1

    def _backward_time(self, beta: float) -> float:
        if beta >= 0.8:
            return 0.65
        if beta >= 0.5:
            return 0.75
        return 0.85

    def _spent(self, env: FlowTTSEnv, initial_budget: int) -> int:
        return max(0, int(initial_budget - env.budget_left))

"""Baseline controllers from the implementation spec."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError
from flow_autotts.core.state import AnswerRecord


def map_beta(beta: float) -> dict[str, float | int]:
    beta = min(max(float(beta), 0.0), 1.0)
    return {
        "max_particles": int(2 + 14 * beta),
        "max_preview_calls": int(2 + 12 * beta),
        "max_backward_children": int(1 + 4 * beta),
        "min_keep": int(1 + 3 * beta),
        "early_time": 0.25,
        "mid_time": 0.55,
        "late_time": 0.80,
    }


class DeterministicController:
    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        particle_id = env.spawn(1)[0]
        for target_time in env.time_grid[1:]:
            env.forward(particle_id, target_time=target_time, solver="euler")
        return env.answer(rule="latest_active")


class BestOfNController:
    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        requested = int(map_beta(beta)["max_particles"])
        per_particle_cost = max(1, len(env.time_grid) - 1) + 1
        affordable = max(1, env.budget // per_particle_cost)
        n = min(requested, affordable)
        ids = env.spawn(n)

        for particle_id in ids:
            for target_time in env.time_grid[1:]:
                env.forward(particle_id, target_time=target_time, solver="euler")
            env.preview(particle_id, scorer="default")

        return env.answer(rule="best_preview_score")


class SDEForwardController:
    """Best-of-N controller using Flow-GRPO-style SDE forward steps."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        requested = int(2 + 14 * beta)
        per_particle_cost = max(1, len(env.time_grid) - 1) + 1
        affordable = max(1, env.budget // per_particle_cost)
        n = min(requested, affordable)
        noise_scale = self._noise_scale(beta)
        ids = env.spawn(n)

        for particle_id in ids:
            for target_time in env.time_grid[1:]:
                env.forward(
                    particle_id,
                    target_time=target_time,
                    solver="sde",
                    cfg={"noise_scale": noise_scale, "sigma_max": 1.25, "min_time": 0.02},
                )
            env.preview(particle_id, scorer="default")

        return env.answer(rule="best_preview_score")

    @staticmethod
    def _noise_scale(beta: float) -> float:
        if beta <= 0.0:
            return 0.03
        if beta < 0.5:
            return 0.0
        if beta < 0.75:
            return 0.01
        return 0.008


class SelfRefineController:
    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        refinement_rounds = int(1 + 3 * beta)
        particle_id = env.spawn(1)[0]

        for target_time in env.time_grid[1:]:
            state = env.get_state().particles[particle_id]
            current_time = state.time
            if current_time < 0.35:
                for _ in range(refinement_rounds):
                    preview = env.preview(
                        particle_id,
                        mode="clean_anchor",
                        scorer=None,
                    )
                    particle_id = env.backward(
                        preview.id,
                        target_time=current_time,
                        noise_policy="fresh_noise",
                        num_children=1,
                    )[0]
            env.forward(particle_id, target_time=target_time, solver="euler")

        return env.answer(rule="latest_active")


class PrismStyleFlowController:
    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        params = map_beta(beta)
        warm_target = float(params["mid_time"])
        finish_grid = [t for t in env.time_grid if t > warm_target]
        if not finish_grid or finish_grid[-1] < 1.0:
            finish_grid.append(1.0)

        per_root_cost = 2
        requested_roots = int(params["max_particles"])
        root_budget = max(1, env.budget // max(1, per_root_cost + len(finish_grid)))
        root_count = min(requested_roots, root_budget)
        ids = env.spawn(root_count)

        previewed_ids: list[int] = []
        for particle_id in ids:
            if env.budget_left < per_root_cost:
                break
            env.forward(particle_id, target_time=warm_target, solver="euler")
            env.preview(particle_id, mode="clean_anchor", scorer="default")
            previewed_ids.append(particle_id)

        if not previewed_ids:
            return env.answer(rule="latest_active")

        state = env.get_state()
        ranked = sorted(
            previewed_ids,
            key=lambda pid: (
                state.previews[state.particles[pid].last_preview_id].score
                if state.particles[pid].last_preview_id is not None
                and state.previews[state.particles[pid].last_preview_id].score is not None
                else float("-inf")
            ),
            reverse=True,
        )
        keep = min(len(ranked), int(params["min_keep"]))
        survivors = ranked[:keep]
        env.prune([pid for pid in ranked if pid not in survivors])

        child_ids: list[int] = []
        children_per_anchor = int(params["max_backward_children"])
        for particle_id in survivors:
            preview_id = env.get_state().particles[particle_id].last_preview_id
            if preview_id is None:
                continue
            child_ids.extend(
                env.backward(
                    preview_id,
                    target_time=warm_target,
                    noise_policy="fresh_noise",
                    num_children=children_per_anchor,
                )
            )

        if not child_ids:
            return env.answer(rule="best_preview_score")

        finished: list[int] = []
        for particle_id in child_ids:
            needed = len([t for t in finish_grid if t > warm_target])
            if env.budget_left < needed + 1:
                break
            try:
                for target_time in finish_grid:
                    if env.get_state().particles[particle_id].status == "active":
                        env.forward(particle_id, target_time=target_time, solver="euler")
                env.preview(particle_id, scorer="default")
                finished.append(particle_id)
            except BudgetExceededError:
                break

        if not finished:
            return env.answer(rule="best_preview_score")
        return env.answer(rule="best_preview_score")

"""Environment exceptions."""


class FlowTTSError(RuntimeError):
    """Base class for environment failures."""


class BudgetExceededError(FlowTTSError):
    """Raised when an action would exceed the episode budget."""


class InvalidActionError(FlowTTSError):
    """Raised when a controller requests an invalid action."""

"""Candidate controller for SD3.5 PickScore discovery."""

from __future__ import annotations

from flow_autotts.core.env import FlowTTSEnv
from flow_autotts.core.errors import BudgetExceededError, InvalidActionError
from flow_autotts.core.state import AnswerRecord, PreviewRecord


class OptimalController:
    """Scout width first, then confirm, then locally refine uncertain winners."""

    def solve(self, env: FlowTTSEnv, beta: float) -> AnswerRecord:
        beta = min(max(float(beta), 0.0), 1.0)
        schedule = self._schedule(env, beta)

        if beta <= 0.0:
            return self._deterministic_answer(env)

        try:
            root_ids = env.spawn(int(schedule["roots"]))
            self._advance_batch(env, root_ids, float(schedule["scout_time"]))
            self._preview_batch(env, root_ids)

            ranked = self._ranked_previews(env)
            if not ranked:
                return self._answer(env)

            keep_ids = self._select_survivors(ranked, schedule)
            self._prune_except(env, root_ids, keep_ids)

            self._confirm_survivors(env, keep_ids, schedule)
            ranked = self._ranked_previews(env)
            if not ranked:
                return self._answer(env)

            self._finish_selected_roots(env, ranked, schedule)
            ranked = self._ranked_previews(env)
            if not ranked:
                return self._answer(env)

            self._refine_with_backward(env, ranked, schedule)
            ranked = self._ranked_previews(env)
            if not ranked:
                return self._answer(env)

            self._late_rechecks(env, ranked, schedule)
        except (BudgetExceededError, InvalidActionError):
            return self._answer(env)

        return self._answer(env)

    def _schedule(self, env: FlowTTSEnv, beta: float) -> dict[str, float | int]:
        grid_last = max(1, len(env.time_grid) - 1)

        if beta <= 0.0:
            return {
                "roots": 1,
                "scout_time": 1.0,
                "confirm_time": 1.0,
                "finish_time": 1.0,
                "branch_time": 0.85,
                "keep": 1,
                "finish_roots": 1,
                "branch_anchors": 0,
                "children": 0,
                "late_passes": 0,
                "score_gap": 0.02,
                "finish_gap": 0.02,
                "branch_gap": 0.01,
                "uncertainty": 0.45,
                "noise_policy": "inferred_noise",
                "noise_strength": 0.55,
            }

        scout_fraction = 0.20 + 0.10 * beta
        confirm_fraction = 0.52 + 0.18 * beta
        finish_fraction = 0.88 + 0.10 * beta

        roots = 2 + int(beta >= 0.35) + int(beta >= 0.65) + int(beta >= 0.90)
        keep = 1 + int(beta >= 0.22) + int(beta >= 0.60) + int(beta >= 0.88)
        finish_roots = 1 + int(beta >= 0.50) + int(beta >= 0.82)
        branch_anchors = int(beta >= 0.28) + int(beta >= 0.58) + int(beta >= 0.88)
        children = int(beta >= 0.28) + int(beta >= 0.72) + int(beta >= 0.92)
        late_passes = int(beta >= 0.58) + int(beta >= 0.86)

        branch_fraction = 0.82 - 0.18 * beta
        branch_fraction = max(0.58, min(branch_fraction, 0.86))
        noise_policy = "inferred_noise" if beta < 0.42 else "mixed_noise"
        noise_strength = 0.58 - 0.22 * beta

        return {
            "roots": roots,
            "scout_time": self._grid_time(env, self._grid_index(grid_last, scout_fraction)),
            "confirm_time": self._grid_time(env, self._grid_index(grid_last, confirm_fraction)),
            "finish_time": self._grid_time(env, self._grid_index(grid_last, finish_fraction)),
            "branch_time": self._grid_time(env, self._grid_index(grid_last, branch_fraction)),
            "keep": keep,
            "finish_roots": finish_roots,
            "branch_anchors": branch_anchors,
            "children": children,
            "late_passes": late_passes,
            "score_gap": 0.010 + 0.010 * beta,
            "finish_gap": 0.018 + 0.010 * beta,
            "branch_gap": 0.006 + 0.010 * beta,
            "uncertainty": 0.18 + 0.16 * beta,
            "noise_policy": noise_policy,
            "noise_strength": max(0.20, noise_strength),
        }

    def _deterministic_answer(self, env: FlowTTSEnv) -> AnswerRecord:
        root_id = env.spawn(1)[0]
        try:
            self._advance_particle(env, root_id, 1.0)
        except (BudgetExceededError, InvalidActionError):
            return env.answer(rule="latest_active")
        return env.answer(rule="latest_active")

    def _advance_batch(self, env: FlowTTSEnv, particle_ids: list[int], target_time: float) -> None:
        for particle_id in particle_ids:
            self._advance_particle(env, particle_id, target_time)

    def _advance_particle(self, env: FlowTTSEnv, particle_id: int, target_time: float) -> None:
        state = env.get_state()
        particle = state.particles.get(particle_id)
        if particle is None or particle.status == "pruned":
            return

        current_time = float(particle.time)
        for grid_time in env.time_grid:
            grid_time = float(grid_time)
            if grid_time > current_time + 1e-9 and grid_time <= target_time + 1e-9:
                env.forward(particle_id, target_time=grid_time, solver="euler")
                current_time = grid_time

    def _preview_batch(self, env: FlowTTSEnv, particle_ids: list[int]) -> None:
        for particle_id in particle_ids:
            if env.budget_left <= 0:
                return
            try:
                env.preview(particle_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                return

    def _select_survivors(
        self,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> set[int]:
        if not ranked:
            return set()

        keep = int(schedule["keep"])
        gap = self._score_gap(ranked)
        top_uncertainty = float(ranked[0].uncertainty or 0.0)
        if gap <= float(schedule["score_gap"]):
            keep += 1
        if top_uncertainty >= float(schedule["uncertainty"]):
            keep += 1
        keep = min(len(ranked), max(1, keep))
        return {preview.particle_id for preview in ranked[:keep]}

    def _prune_except(self, env: FlowTTSEnv, particle_ids: list[int], keep_ids: set[int]) -> None:
        losers = [particle_id for particle_id in particle_ids if particle_id not in keep_ids]
        if not losers:
            return
        try:
            env.prune(losers)
        except InvalidActionError:
            return

    def _confirm_survivors(
        self,
        env: FlowTTSEnv,
        keep_ids: set[int],
        schedule: dict[str, float | int],
    ) -> None:
        target_time = float(schedule["confirm_time"])
        for particle_id in list(keep_ids):
            if env.budget_left <= 0:
                return
            state = env.get_state()
            particle = state.particles.get(particle_id)
            if particle is None or particle.status == "pruned":
                continue
            try:
                self._advance_particle(env, particle_id, target_time)
                if env.budget_left > 0:
                    env.preview(particle_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                continue

    def _finish_selected_roots(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> None:
        if not ranked:
            return

        finish_count = min(len(ranked), max(1, int(schedule["finish_roots"])))
        gap = self._score_gap(ranked)
        top_uncertainty = float(ranked[0].uncertainty or 0.0)
        if gap <= float(schedule["finish_gap"]):
            finish_count = min(len(ranked), finish_count + 1)
        if top_uncertainty >= float(schedule["uncertainty"]):
            finish_count = min(len(ranked), finish_count + 1)

        for preview in ranked[:finish_count]:
            if env.budget_left <= 0:
                return
            try:
                self._advance_particle(env, preview.particle_id, 1.0)
                if env.budget_left > 0:
                    env.preview(preview.particle_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                continue

    def _refine_with_backward(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
    ) -> None:
        anchor_budget = int(schedule["branch_anchors"])
        child_budget = int(schedule["children"])
        if anchor_budget <= 0 or child_budget <= 0 or not ranked:
            return

        chosen = self._choose_branch_anchors(ranked, schedule, anchor_budget)
        target_time = float(schedule["branch_time"])
        finish_time = float(schedule["finish_time"])

        for index, anchor in enumerate(chosen):
            if env.budget_left <= 0:
                return

            num_children = child_budget
            if index > 0:
                num_children = max(1, num_children - 1)
            if (
                index == 0
                and len(ranked) > 1
                and self._score_gap(ranked) <= float(schedule["branch_gap"])
            ):
                num_children += 1

            try:
                child_ids = env.backward(
                    anchor.id,
                    target_time=target_time,
                    noise_policy=str(schedule["noise_policy"]),
                    num_children=num_children,
                    strength=float(schedule["noise_strength"]),
                )
            except (BudgetExceededError, InvalidActionError):
                return

            for child_id in child_ids:

            if env.budget_left <= 0:
                return
            try:
                self._advance_particle(env, child_id, finish_time)
                if env.budget_left > 0:
                    env.preview(child_id, mode="clean_anchor", scorer="default")
            except (BudgetExceededError, InvalidActionError):
                return

        self._prune_clear_losers(env)

def _late_rechecks(
    self,
    env: FlowTTSEnv,
    ranked: list[PreviewRecord],
    schedule: dict[str, float | int],
) -> None:
    passes = int(schedule["late_passes"])
    if passes <= 0 or not ranked:
        return

    for round_index in range(passes):
        current_ranked = self._ranked_previews(env)
        if not current_ranked or env.budget_left <= 0:
            return
        gap = self._score_gap(current_ranked)
        top_uncertainty = float(current_ranked[0].uncertainty or 0.0)
        if gap > float(schedule["finish_gap"]) and top_uncertainty < float(schedule["uncertainty"]):
            return

        preview = current_ranked[min(round_index, len(current_ranked) - 1)]
        try:
            if env.budget_left > 0:
                env.preview(preview.particle_id, mode="clean_anchor", scorer="default")
        except (BudgetExceededError, InvalidActionError):
            return

def _choose_branch_anchors(
    self,
    ranked: list[PreviewRecord],
    schedule: dict[str, float | int],
    anchor_budget: int,
) -> list[PreviewRecord]:
    if not ranked or anchor_budget <= 0:
        return []

    chosen = [ranked[0]]
    gap = self._score_gap(ranked)
    top_uncertainty = float(ranked[0].uncertainty or 0.0)

    if gap <= float(schedule["branch_gap"]) or top_uncertainty >= float(schedule["uncertainty"]):
        for preview in ranked[1:]:
            if len(chosen) >= anchor_budget:
                break
            chosen.append(preview)

    return chosen[:anchor_budget]

def _prune_clear_losers(self, env: FlowTTSEnv) -> None:
    ranked = self._ranked_previews(env)
    if len(ranked) < 3:
        return

    best_score = float(ranked[0].score or 0.0)
    losers = [
        preview.particle_id
        for preview in ranked[2:]
        if best_score - float(preview.score or 0.0) > 0.030
    ]
    if not losers:
        return
    try:
        env.prune(losers)
    except InvalidActionError:
        return

def _ranked_previews(self, env: FlowTTSEnv) -> list[PreviewRecord]:
    state = env.get_state()
    previews_by_particle: dict[int, PreviewRecord] = {}
    for particle in state.particles.values():
        if particle.status == "pruned" or particle.last_preview_id is None:
            continue
        preview = state.previews.get(particle.last_preview_id)
        if preview is None or preview.score is None:
            continue
        previews_by_particle[particle.id] = preview
    return sorted(
        previews_by_particle.values(),
        key=lambda preview: (
            float(preview.score),
            -float(preview.uncertainty or 0.0),
            float(preview.time),
        ),
        reverse=True,
    )

def _score_gap(self, ranked: list[PreviewRecord]) -> float:
    if len(ranked) < 2:
        return float("inf")
    return float(ranked[0].score or 0.0) - float(ranked[1].score or 0.0)

def _grid_index(self, grid_last: int, fraction: float) -> int:
    fraction = min(max(float(fraction), 0.0), 1.0)
    return min(grid_last, max(1, int(round(grid_last * fraction))))

def _grid_time(self, env: FlowTTSEnv, index: int) -> float:
    index = min(max(0, int(index)), len(env.time_grid) - 1)
    return float(env.time_grid[index])

def _answer(self, env: FlowTTSEnv) -> AnswerRecord:
    state = env.get_state()
    if state.previews:
        try:
