    def _top_off(
        self,
        env: FlowTTSEnv,
        ranked: list[PreviewRecord],
        schedule: dict[str, float | int],
        beta: float,
        initial_budget: int,
        target_nfe: int,
    ) -> None:
        if not ranked or env.budget_left <= 0:
            return
        if self._spent(env, initial_budget) >= target_nfe:
            return
        gap = self._score_gap(ranked)
